423	    @DELETE
424	    @Path("/{bucket}/{key:.+}")
425	    public Response deleteObject(@PathParam("bucket") String bucket,
426	                                 @PathParam("key") String key,
427	                                 @QueryParam("uploadId") String uploadId,
428	                                 @QueryParam("versionId") String versionId,
429	                                 @Context UriInfo uriInfo,
430	                                 @Context HttpHeaders httpHeaders) {
431	        try {
432	            if (hasQueryParam(uriInfo, "tagging")) {
433	                s3Service.deleteObjectTagging(bucket, key);
434	                return Response.noContent().build();
435	            }
436	            if (uploadId != null) {
437	                s3Service.abortMultipartUpload(bucket, key, uploadId);
438	                return Response.noContent().build();
439	            }
440	            boolean bypass = "true".equalsIgnoreCase(
441	                    httpHeaders.getHeaderString("x-amz-bypass-governance-retention"));
442	            S3Object result = s3Service.deleteObject(bucket, key, versionId, bypass);
443	            var resp = Response.noContent();
444	            if (result != null && result.isDeleteMarker()) {
445	                resp.header("x-amz-delete-marker", "true");
446	                resp.header("x-amz-version-id", result.getVersionId());
447	            }
448	            return resp.build();
449	        } catch (AwsException e) {
450	            return xmlErrorResponse(e);
451	        }
452	    }
