1030	                    .elem("ChecksumCRC32C", part.getChecksum().getChecksumCRC32C())
1031	                    .elem("ChecksumCRC64NVME", part.getChecksum().getChecksumCRC64NVME())
1032	                    .elem("ChecksumSHA1", part.getChecksum().getChecksumSHA1())
1033	                    .elem("ChecksumSHA256", part.getChecksum().getChecksumSHA256())
