352	    public S3Object deleteObject(String bucketName, String key, String versionId, boolean bypassGovernance) {
353	        Bucket bucket = bucketStore.get(bucketName)
354	                .orElseThrow(() -> new AwsException("NoSuchBucket",
355	                        "The specified bucket does not exist.", 404));
356	
357	        if (bucket.isVersioningEnabled() && versionId == null) {
358	            // Check lock on current latest before placing a delete marker
359	            objectStore.get(objectKey(bucketName, key)).ifPresent(prev -> {
360	                if (!prev.isDeleteMarker()) {
361	                    checkLockProtection(prev, bypassGovernance);
362	                }
363	            });
364	
365	            // Create a delete marker instead of actually deleting
366	            S3Object deleteMarker = new S3Object(bucketName, key, new byte[0], null);
367	            String markerId = UUID.randomUUID().toString();
368	            deleteMarker.setVersionId(markerId);
369	            deleteMarker.setDeleteMarker(true);
370	            deleteMarker.setLatest(true);
371	
372	            // Mark previous latest as not latest
373	            objectStore.get(objectKey(bucketName, key)).ifPresent(prev -> {
374	                if (prev.getVersionId() != null) {
375	                    prev.setLatest(false);
376	                    objectStore.put(versionedKey(bucketName, key, prev.getVersionId()), prev);
377	                }
378	            });
379	
380	            objectStore.put(versionedKey(bucketName, key, markerId), deleteMarker);
381	            objectStore.put(objectKey(bucketName, key), deleteMarker);
382	            LOG.debugv("Created delete marker: {0}/{1} v={2}", bucketName, key, markerId);
383	            fireNotifications(bucketName, key, "ObjectRemoved:DeleteMarkerCreated", deleteMarker);
384	            return deleteMarker;
385	        } else if (versionId != null) {
386	            // Check lock on the specific version before permanent deletion
387	            objectStore.get(versionedKey(bucketName, key, versionId)).ifPresent(obj -> {
388	                if (!obj.isDeleteMarker()) {
389	                    checkLockProtection(obj, bypassGovernance);
390	                }
391	            });
392	            // Permanently delete a specific version
393	            objectStore.delete(versionedKey(bucketName, key, versionId));
394	            LOG.debugv("Permanently deleted version: {0}/{1} v={2}", bucketName, key, versionId);
395	            return null;
396	        } else {
397	            // Check lock on the non-versioned object before delete
398	            objectStore.get(objectKey(bucketName, key)).ifPresent(obj -> {
399	                if (!obj.isDeleteMarker()) {
400	                    checkLockProtection(obj, bypassGovernance);
401	                }
402	            });
403	            // Non-versioned delete
404	            objectStore.delete(objectKey(bucketName, key));
405	            deleteFile(bucketName, key);
406	            LOG.debugv("Deleted object: {0}/{1}", bucketName, key);
407	            fireNotifications(bucketName, key, "ObjectRemoved:Delete", null);
408	            return null;
409	        }
410	    }
