494	    public List<S3Object> listObjectVersions(String bucketName, String prefix, int maxKeys) {
495	        ensureBucketExists(bucketName);
496	
497	        String versionPrefix = bucketName + "/";
498	        String fullPrefix = prefix != null ? versionPrefix + prefix : versionPrefix;
499	
500	        // Scan for versioned entries (contain #v#)
501	        List<S3Object> versions = new ArrayList<>(objectStore.scan(key ->
502	                key.startsWith(fullPrefix) && key.contains("#v#")));
503	
504	        // Sort by key, then by lastModified descending
505	        versions.sort((a, b) -> {
506	            int keyCompare = a.getKey().compareTo(b.getKey());
507	            if (keyCompare != 0) return keyCompare;
508	            return b.getLastModified().compareTo(a.getLastModified());
509	        });
510	
511	        if (maxKeys > 0 && versions.size() > maxKeys) {
512	            versions = versions.subList(0, maxKeys);
513	        }
514	        return versions;
515	    }
