648	    public void putObjectRetention(String bucketName, String key, String versionId,
649	                                   String mode, Instant retainUntil, boolean bypassGovernance) {
650	        ensureBucketExists(bucketName);
651	        String storeKey = versionId != null
652	                ? versionedKey(bucketName, key, versionId)
653	                : objectKey(bucketName, key);
654	        S3Object obj = objectStore.get(storeKey)
655	                .orElseThrow(() -> new AwsException("NoSuchKey",
656	                        "The specified key does not exist.", 404));
657	
658	        // COMPLIANCE mode: retainUntil cannot be shortened
659	        if ("COMPLIANCE".equals(obj.getObjectLockMode())
660	                && obj.getRetainUntilDate() != null
661	                && retainUntil != null
662	                && retainUntil.isBefore(obj.getRetainUntilDate())) {
663	            throw new AwsException("AccessDenied",
664	                    "COMPLIANCE retention period cannot be shortened", 403);
665	        }
666	
667	        // Check bypass permission for existing governance lock when shortening/removing
668	        if ("GOVERNANCE".equals(obj.getObjectLockMode())
669	                && obj.getRetainUntilDate() != null
670	                && Instant.now().isBefore(obj.getRetainUntilDate())
671	                && !bypassGovernance) {
672	            if (retainUntil == null || retainUntil.isBefore(obj.getRetainUntilDate())) {
673	                throw new AwsException("AccessDenied",
674	                        "Object is protected by GOVERNANCE retention", 403);
675	            }
676	        }
677	
678	        obj.setObjectLockMode(mode);
679	        obj.setRetainUntilDate(retainUntil);
680	        objectStore.put(storeKey, obj);
681	        LOG.debugv("Set retention on {0}/{1}: mode={2}, until={3}", bucketName, key, mode, retainUntil);
682	    }
