743	    public String uploadPart(String bucket, String key, String uploadId, int partNumber, byte[] data) {
744	        MultipartUpload upload = multipartUploads.get(uploadId);
745	        if (upload == null || !upload.getBucket().equals(bucket) || !upload.getKey().equals(key)) {
746	            throw new AwsException("NoSuchUpload",
747	                    "The specified multipart upload does not exist.", 404);
748	        }
749	        if (partNumber < 1 || partNumber > 10000) {
750	            throw new AwsException("InvalidArgument",
751	                    "Part number must be between 1 and 10000.", 400);
752	        }
753	
754	        // Write part to temp directory
755	        Path partPath = dataRoot.resolve(".multipart").resolve(uploadId).resolve(String.valueOf(partNumber));
756	        try {
757	            Files.write(partPath, data);
758	        } catch (IOException e) {
759	            throw new UncheckedIOException("Failed to write multipart part", e);
760	        }
761	
762	        String eTag = computeETag(data);
763	        Part part = new Part(partNumber, eTag, data.length);
764	        part.setChecksum(buildChecksum(data, List.of(part), true));
765	        upload.getParts().put(partNumber, part);
766	        LOG.debugv("Uploaded part {0} for upload {1} ({2} bytes)", partNumber, uploadId, data.length);
767	        return eTag;
768	    }
