770	    public S3Object completeMultipartUpload(String bucket, String key, String uploadId, List<Integer> partNumbers) {
771	        MultipartUpload upload = multipartUploads.get(uploadId);
772	        if (upload == null || !upload.getBucket().equals(bucket) || !upload.getKey().equals(key)) {
773	            throw new AwsException("NoSuchUpload",
774	                    "The specified multipart upload does not exist.", 404);
775	        }
776	
777	        // Verify all requested parts exist
778	        for (int num : partNumbers) {
779	            if (!upload.getParts().containsKey(num)) {
780	                throw new AwsException("InvalidPart",
781	                        "One or more of the specified parts could not be found. Part " + num + " is missing.", 400);
782	            }
783	        }
784	
785	        // Concatenate parts in order
786	        try {
787	            ByteArrayOutputStream combined = new ByteArrayOutputStream();
788	            MessageDigest md = MessageDigest.getInstance("MD5");
789	
790	            for (int num : partNumbers) {
791	                Path partPath = dataRoot.resolve(".multipart").resolve(uploadId).resolve(String.valueOf(num));
792	                byte[] partData = Files.readAllBytes(partPath);
793	                combined.write(partData);
794	                // For composite ETag: hash each part's MD5
795	                md.update(computeETagBytes(partData));
796	            }
797	
798	            byte[] allData = combined.toByteArray();
799	
800	            // Composite ETag: MD5 of concatenated part MD5s, suffixed with part count
801	            String compositeETag = "\"" + bytesToHex(md.digest()) + "-" + partNumbers.size() + "\"";
802	
803	            List<Part> completedParts = partNumbers.stream()
804	                    .map(num -> copyPart(upload.getParts().get(num)))
805	                    .toList();
806	            S3Checksum checksum = buildChecksum(allData, completedParts, true);
807	            S3Object object = storeObject(bucket, key, allData, upload.getContentType(), upload.getMetadata(),
808	                    upload.getStorageClass(), checksum, completedParts, null, null, null);
809	            // Override the ETag with the composite multipart ETag
810	            object.setETag(compositeETag);
811	            objectStore.put(objectKey(bucket, key), object);
812	
813	            // Cleanup
814	            cleanupMultipart(uploadId);
815	            LOG.infov("Completed multipart upload: {0}/{1}, uploadId={2}, parts={3}",
816	                    bucket, key, uploadId, partNumbers.size());
817	            fireNotifications(bucket, key, "ObjectCreated:CompleteMultipartUpload", object);
818	            return object;
819	        } catch (IOException e) {
820	            throw new UncheckedIOException("Failed to read multipart parts", e);
821	        } catch (NoSuchAlgorithmException e) {
822	            throw new RuntimeException("MD5 algorithm not available", e);
823	        }
824	    }
