1008	    private void fireNotifications(String bucketName, String key, String eventName, S3Object obj) {
1009	        if (sqsService == null && snsService == null) {
1010	            return;
1011	        }
1012	        Bucket bucket = bucketStore.get(bucketName).orElse(null);
1013	        if (bucket == null) {
1014	            return;
1015	        }
1016	        NotificationConfiguration config = bucket.getNotificationConfiguration();
1017	        if (config == null || config.isEmpty()) {
1018	            return;
1019	        }
1020	
1021	        String region = regionResolver != null ? regionResolver.getDefaultRegion() : "us-east-1";
1022	        String eventJson = buildS3EventJson(bucketName, key, eventName, obj, region);
1023	
1024	        for (QueueNotification qn : config.getQueueConfigurations()) {
1025	            if (qn.events().stream().anyMatch(p -> matchesEvent(p, eventName))) {
1026	                try {
1027	                    sqsService.sendMessage(sqsUrlFromArn(qn.queueArn()), eventJson, 0);
1028	                    LOG.debugv("Fired S3 event {0} to SQS {1}", eventName, qn.queueArn());
1029	                } catch (Exception e) {
1030	                    LOG.warnv("Failed to deliver S3 event to SQS {0}: {1}", qn.queueArn(), e.getMessage());
1031	                }
1032	            }
1033	        }
1034	
1035	        for (TopicNotification tn : config.getTopicConfigurations()) {
1036	            if (tn.events().stream().anyMatch(p -> matchesEvent(p, eventName))) {
1037	                try {
1038	                    snsService.publish(tn.topicArn(), null, eventJson, "Amazon S3 Notification", region);
1039	                    LOG.debugv("Fired S3 event {0} to SNS {1}", eventName, tn.topicArn());
1040	                } catch (Exception e) {
1041	                    LOG.warnv("Failed to deliver S3 event to SNS {0}: {1}", tn.topicArn(), e.getMessage());
1042	                }
1043	            }
1044	        }
1045	    }
