1047	    private boolean matchesEvent(String pattern, String eventName) {
1048	        String full = "s3:" + eventName;
1049	        if (pattern.endsWith("*")) {
1050	            return full.startsWith(pattern.substring(0, pattern.length() - 1));
1051	        }
1052	        return full.equals(pattern);
1053	    }
