1060	    private String buildS3EventJson(String bucketName, String key, String eventName,
1061	                                    S3Object obj, String region) {
1062	        try {
1063	            String eventTime = DateTimeFormatter.ISO_INSTANT.format(Instant.now());
1064	            long size = obj != null ? obj.getSize() : 0;
1065	            String eTag = obj != null && obj.getETag() != null ? obj.getETag().replace("\"", "") : "";
1066	            String requestId = UUID.randomUUID().toString();
1067	
1068	            ObjectNode bucketNode = objectMapper.createObjectNode();
1069	            bucketNode.put("name", bucketName);
1070	            bucketNode.put("arn", "arn:aws:s3:::" + bucketName);
1071	
1072	            ObjectNode objectNode = objectMapper.createObjectNode();
1073	            objectNode.put("key", key);
1074	            objectNode.put("size", size);
1075	            objectNode.put("eTag", eTag);
1076	
1077	            ObjectNode s3Node = objectMapper.createObjectNode();
1078	            s3Node.put("s3SchemaVersion", "1.0");
1079	            s3Node.put("configurationId", "emulator");
1080	            s3Node.set("bucket", bucketNode);
1081	            s3Node.set("object", objectNode);
1082	
1083	            ObjectNode record = objectMapper.createObjectNode();
1084	            record.put("eventVersion", "2.1");
1085	            record.put("eventSource", "aws:s3");
1086	            record.put("awsRegion", region);
1087	            record.put("eventTime", eventTime);
1088	            record.put("eventName", eventName);
1089	            record.putObject("userIdentity").put("principalId", "AWS:EMULATOR");
1090	            record.putObject("requestParameters").put("sourceIPAddress", "127.0.0.1");
1091	            record.putObject("responseElements").put("x-amz-request-id", requestId);
1092	            record.set("s3", s3Node);
1093	
1094	            ObjectNode root = objectMapper.createObjectNode();
1095	            root.putArray("Records").add(record);
1096	            return objectMapper.writeValueAsString(root);
1097	        } catch (Exception e) {
1098	            return "{\"Records\":[]}";
1099	        }
1100	    }
