1107	    private static S3Checksum buildChecksum(byte[] data, List<Part> parts, boolean multipartUpload) {
1108	        S3Checksum checksum = new S3Checksum();
1109	        checksum.setChecksumSHA1(S3Checksum.sha1Base64(data));
1110	        checksum.setChecksumSHA256(S3Checksum.sha256Base64(data));
1111	        checksum.setChecksumType(multipartUpload || (parts != null && parts.size() > 1)
1112	                ? "COMPOSITE"
1113	                : "FULL_OBJECT");
1114	        return checksum;
1115	    }
