package org.junit.jupiter.api;

import io.quarkus.test.junit.QuarkusTest;
import org.junit.jupiter.api.MethodOrderer;
import org.junit.jupiter.api.Order;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.TestMethodOrder;

import static io.restassured.RestAssured.given;
import static org.hamcrest.Matchers.*;

@QuarkusTest
@TestMethodOrder(MethodOrderer.OrderAnnotation.class)
class S3VirtualHostIntegrationTest {

    @Test
    @Order(1)
    void createBucket_virtualHost_localhost() {
        String bucket = "vh-localhost";
        given()
            .header("Host", bucket + ".localhost")
        .when()
            .put("/")
        .then()
            .statusCode(200)
            .header("Location", equalTo("/" + bucket));

        // cleanup
        given().header("Host", bucket + ".localhost").when().delete("/");
    }

    @Test
    @Order(2)
    void putAndGetObject_virtualHost_localhost() {
        String bucket = "vh-obj-local";
        given().header("Host", bucket + ".localhost").when().put("/").then().statusCode(200);

        given()
            .header("Host", bucket + ".localhost")
            .contentType("text/plain")
            .body("test data")
        .when()
            .put("/test.txt")
        .then()
            .statusCode(200)
            .header("ETag", notNullValue());

        given()
            .header("Host", bucket + ".localhost")
        .when()
            .get("/test.txt")
        .then()
            .statusCode(200)
            .body(equalTo("test data"));

        // cleanup
        given().header("Host", bucket + ".localhost").when().delete("/test.txt");
        given().header("Host", bucket + ".localhost").when().delete("/");
    }

    @Test
    @Order(3)
    void virtualHost_s3_amazonaws_pattern() {
        // Simulates: bucket.s3.amazonaws.com
        String bucket = "vh-s3-amazonaws";
