package org.junit.jupiter.api;

import io.quarkus.test.junit.QuarkusTest;
import org.junit.jupiter.api.Test;

import static io.restassured.RestAssured.given;
import static org.hamcrest.Matchers.*;

@QuarkusTest
class S3VirtualHostIntegrationTest {

    @Test
    void test_all_virtual_host_operations() {
        String bucket = "vht-all";

        // Create bucket
        given().header("Host", bucket + ".localhost")
            .when().put("/").then().statusCode(200);

        // Put object
        given().header("Host", bucket + ".localhost")
            .contentType("text/plain").body("hello")
            .when().put("/obj.txt").then().statusCode(200);

        // Get object
        given().header("Host", bucket + ".localhost")
            .when().get("/obj.txt").then().statusCode(200).body(equalTo("hello"));

        // Head object
        given().header("Host", bucket + ".localhost")
            .when().head("/obj.txt").then().statusCode(200);

        // List objects
        given().header("Host", bucket + ".localhost")
            .when().get("/").then().statusCode(200).body(containsString("obj.txt"));

        // Copy object
        given().header("Host", bucket + ".localhost")
            .header("x-amz-copy-source", "/" + bucket + "/obj.txt")
            .when().put("/obj-copy.txt").then().statusCode(200)
            .body(containsString("CopyObjectResult"));

        // Delete object
        given().header("Host", bucket + ".localhost")
            .when().delete("/obj-copy.txt").then().statusCode(204);

        // Delete bucket (with remaining obj.txt)
        given().header("Host", bucket + ".localhost")
            .when().delete("/obj.txt").then().statusCode(204);

        given().header("Host", bucket + ".localhost")
            .when().delete("/").then().statusCode(204);
    }
}

