package org.junit.jupiter.api;

import io.quarkus.test.junit.QuarkusTest;
import org.junit.jupiter.api.Test;

import static io.restassured.RestAssured.given;
import static org.hamcrest.Matchers.*;

@QuarkusTest
class S3VirtualHostIntegrationTest {

    @Test
    void virtualHost_subResource_queries_work() {
        String bucket = "vh-subresource";
        // Create bucket via virtual host
        given().header("Host", bucket + ".localhost").when().put("/").then().statusCode(200);

        // Test ?location
        given()
            .header("Host", bucket + ".localhost")
            .queryParam("location", "")
        .when()
            .get("/")
        .then()
            .statusCode(200)
            .body(containsString("LocationConstraint"));

        // Test ?versioning (GET)
        given()
            .header("Host", bucket + ".localhost")
            .queryParam("versioning", "")
        .when()
            .get("/")
        .then()
            .statusCode(200)
            .body(containsString("VersioningConfiguration"));

        // Test ?versioning (PUT)
        String xml = """
            <VersioningConfiguration xmlns="http://s3.amazonaws.com/doc/2006-03-01/">
                <Status>Enabled</Status>
            </VersioningConfiguration>
            """;
        given()
            .header("Host", bucket + ".localhost")
            .queryParam("versioning", "")
            .contentType("application/xml")
            .body(xml)
        .when()
            .put("/")
        .then()
            .statusCode(200);

        // Test ?tagging (PUT)
        String taggingXml = """
            <Tagging xmlns="http://s3.amazonaws.com/doc/2006-03-01/">
                <TagSet>
                    <Tag><Key>env</Key><Value>test</Value></Tag>
                </TagSet>
            </Tagging>
            """;
        given()
            .header("Host", bucket + ".localhost")
            .queryParam("tagging", "")
            .contentType("application/xml")
            .body(taggingXml)
        .when()
            .put("/")
        .then()
            .statusCode(204);

        // Test ?tagging (GET)
        given()
            .header("Host", bucket + ".localhost")
            .queryParam("tagging", "")
        .when()
            .get("/")
        .then()
            .statusCode(200)
            .body(containsString("env"))
            .body(containsString("test"));

        // Test object tagging via virtual host
        given()
            .header("Host", bucket + ".localhost")
            .contentType("text/plain")
            .body("test")
        .when()
            .put("/obj.txt")
        .then()
            .statusCode(200);

        given()
            .header("Host", bucket + ".localhost")
            .queryParam("tagging", "")
            .contentType("application/xml")
            .body(taggingXml)
        .when()
            .put("/obj.txt")
        .then()
            .statusCode(200);

        given()
            .header("Host", bucket + ".localhost")
            .queryParam("tagging", "")
        .when()
            .get("/obj.txt")
        .then()
            .statusCode(200)
            .body(containsString("env"));

        // Test multipart upload
        given()
            .header("Host", bucket + ".localhost")
            .queryParam("uploads", "")
        .when()
            .post("/multipart.txt")
        .then()
            .statusCode(200)
            .body(containsString("UploadId"));

        // cleanup
        given().header("Host", bucket + ".localhost").when().delete("/obj.txt");
        given().header("Host", bucket + ".localhost").when().delete("/");
    }
}

